queries.sparql:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?genre_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGenres ?child ; p:hasMusic_Festivals ?parent . } GROUP BY ?child }
  ?child p:genre_name ?genre_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Music_Festivals } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?festival_name ?genre_name WHERE {
  ?music_festivals_genres a :Music_Festivals_Genres .
  ?genres a :Genres .
  ?music_festivals_genres p:hasGenres ?genres .
  ?music_festivals a :Music_Festivals .
  ?music_festivals_genres p:hasMusic_Festivals ?music_festivals .
  ?music_festivals p:festival_name ?festival_name .
  ?genres p:genre_name ?genre_name .
} }
  collective: { SELECT ?genre_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGenres ?child ; p:hasMusic_Festivals ?parent . } GROUP BY ?child }
  ?child p:genre_name ?genre_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Music_Festivals } }
  FILTER(?nf = ?total)
} }
}
